import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import IncomeExpandedContent, { INCOME_EXPANDED_FAQS } from "@/components/IncomeExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}


const PLATFORM_FEES: Record<string, number> = {
  "Gumroad": 10,
  "Teachable": 5,
  "Podia": 0,
  "Etsy": 6.5,
  "Shopify": 2.9,
  "Payhip": 5,
  "Custom": 0,
};

const FAQS = [
  { q: "What platform fees should I expect for digital products?", a: "Gumroad: 10% per sale. Teachable: 0-5% depending on plan. Podia: 0% on paid plans. Etsy: 6.5% transaction + listing fees. Shopify: 2.9% + $0.30 + monthly plan fee. Always check current platform pricing as fees change." },
  { q: "What's a good profit margin for digital products?", a: "Since digital products have near-zero marginal cost, healthy margins are 70-95%+. Your main costs are platform fees, payment processing, and marketing. If your margin is below 60%, review your platform choice and pricing strategy." },
  { q: "How should I price my digital product?", a: "Don't price based on cost - price based on value delivered. Research competitors, survey potential buyers, and consider a launch price lower than your long-term price. Most creators underprice; testing higher prices often converts just as well." },
  { q: "Is it better to sell on a marketplace or my own website?", a: "Marketplaces (Etsy, Gumroad) bring built-in traffic but charge higher fees (6-10%). Own website (Shopify, Podia) means you own the audience and keep more revenue, but require your own traffic. Best strategy: start on a marketplace, then migrate top sellers to your own store." },
  { q: "How many sales do I need to replace a $5,000/month salary with digital products?", a: "It depends on your price and platform fee. At $49/product with Gumroad (10% fee): net per sale = $44.10. You'd need 114 sales/month. At $99/product with Podia (0% fee): net = $99 per sale, needing only 51 sales/month." },
  { q: "What types of digital products have the highest margins?", a: "Software and SaaS tools (marginal cost ~$0, margins 80-90%+). Online courses (60-90% margin after platform fees). Ebooks and templates (70-90%). Stock photos and music (60-80%). The key is minimizing per-sale costs while maximizing price." },
  { q: "Should I charge for individual products or use a subscription?", a: "Subscriptions provide predictable recurring revenue but require continuous value delivery. One-time products are easier to sell and require no ongoing commitment. Many successful creators offer both: one-time products plus a membership community or software subscription." },
];

const EXPANDED_FAQS = INCOME_EXPANDED_FAQS.digitalProductProfit;

export default function DigitalProductProfitCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(49);
  const [sales, setSales] = useState(50);
  const [platformKey, setPlatformKey] = useState("Gumroad");
  const [customFee, setCustomFee] = useState(10);

  const feeRate = platformKey === "Custom" ? customFee : PLATFORM_FEES[platformKey];
  const revenue = price * sales;
  const platformFees = revenue * (feeRate / 100);
  const netProfit = revenue - platformFees;
  const margin = revenue > 0 ? (netProfit / revenue) * 100 : 0;
  const annualProfit = netProfit * 12;

  return (
    <>
      <SEOHead
        title="Free Digital Product Profit Calculator Online 2025 - Calculate Net Profit After Fees | CalcHive"
        description="Free digital product profit calculator online. Calculate your exact net profit from digital product sales after platform fees and expenses. 100% free for all creators and sellers, no login needed."
        canonical="/digital-product-profit-calculator"
        keywords="free digital product profit calculator, digital product earnings calculator free online, calculate digital product profit free, digital product fee calculator free, net profit digital products calculator free, online course profit calculator free"
        category="Income"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-violet-600 dark:text-violet-400 bg-violet-50 dark:bg-violet-950/50 px-3 py-1 rounded-full mb-4">Income</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Digital Product Profit Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free digital product profit calculator to calculate digital product profit free from courses, ebooks, templates, and downloads. This digital product earnings calculator free online also works as a digital product fee calculator free, net profit digital products calculator free, and online course profit calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-6">
            <SliderInput id="product-price-dp" label="Product Price" value={price} min={1} max={2000} step={1} onChange={setPrice} format={fmt} testId="input-price" />
            <SliderInput id="monthly-sales-dp" label="Monthly Sales" value={sales} min={1} max={5000} step={1} onChange={setSales} testId="input-sales" helpText="units/month" />
          </div>

          <div className="mb-8">
            <p className="text-sm font-semibold text-foreground mb-3">Platform</p>
            <div className="flex flex-wrap gap-2">
              {Object.keys(PLATFORM_FEES).map(p => (
                <button key={p} onClick={() => setPlatformKey(p)}
                  className={`px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${platformKey === p ? "bg-primary text-primary-foreground border-primary shadow-sm" : "bg-muted text-muted-foreground border-border hover:border-primary/40"}`}>
                  {p} {p !== "Custom" ? `(${PLATFORM_FEES[p]}%)` : ""}
                </button>
              ))}
            </div>
            {platformKey === "Custom" && (
              <div className="mt-4">
                <SliderInput id="custom-fee" label="Custom Platform Fee" value={customFee} min={0} max={50} step={0.1} onChange={setCustomFee} format={v => `${v.toFixed(1)}%`} testId="input-custom-fee" />
              </div>
            )}
          </div>

          <motion.div key={`${price}-${sales}-${feeRate}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-violet-500 to-violet-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Net Profit</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-net">{fmt(netProfit)}</p>
              <p className="text-white/70 text-sm mt-1">{margin.toFixed(1)}% margin - {platformKey} ({feeRate}% fee)</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Gross Revenue", value: fmt(revenue), testId: "result-revenue" },
                { label: "Platform Fees", value: `-platformFees)}`, red: true, testId: "result-fees" },
                { label: "Annual Profit", value: fmt(annualProfit) },
              ].map(({ label, value, red, testId }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-lg font-extrabold ${red ? "text-red-600 dark:text-red-400" : "text-foreground"}`} data-testid={testId}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Digital Product Profit for Free</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Platform", "Transaction Fee", "Monthly Cost", "Net on $49 Sale", "Best For"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Gumroad", "10%", "Free", "$44.10", "Beginners, simple setup"],
                  ["Payhip", "5%", "Free ($0 plan)", "$46.55", "Lower fees than Gumroad"],
                  ["Etsy", "6.5% + $0.20 listing", "Free", "$45.32", "Built-in marketplace traffic"],
                  ["Teachable", "5% (basic plan)", "$39/mo", "$46.55", "Courses and coaching"],
                  ["Podia", "0%", "$33/mo", "$49.00", "Best for volume sellers"],
                  ["Shopify", "2.9% (Shopify Payments)", "$29/mo", "$47.58", "Full ecommerce store"],
                ].map(([platform, fee, monthly, net, bestFor]) => (
                  <tr key={platform} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{platform}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{fee}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{monthly}</td>
                    <td className="py-2.5 px-3 text-violet-600 dark:text-violet-400 font-semibold">{net}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{bestFor}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Platform Fees Affect Your Digital Product Earnings</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Price", "10 sales/mo", "50 sales/mo", "100 sales/mo", "500 sales/mo"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[9, 19, 49, 99, 199, 497].map(p => {
                  const net = p * (1 - feeRate / 100);
                  return (
                    <tr key={p} className="hover:bg-muted/30">
                      <td className="py-2.5 px-3 font-semibold text-foreground">{formatCurrencyValue(p, { maximumFractionDigits: 0 })}</td>
                      {[10, 50, 100, 500].map(s => (
                        <td key={s} className="py-2.5 px-3 text-muted-foreground">{fmt(net * s)}</td>
                      ))}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <p className="text-xs text-muted-foreground">Net profit calculated at {feeRate}% platform fee ({platformKey})</p>
        </section>
        <IncomeExpandedContent kind="digitalProductProfit" />

        <section className="mb-8">
          <h2 className="text-2xl font-bold text-foreground">How to Maximize Profit from Digital Product Sales</h2>
          <p className="text-muted-foreground leading-relaxed">Improve profit by choosing lower-fee platforms, increasing conversion rate, testing price points, and reducing fixed production expenses.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Digital Product Income Calculator for Every Creator</h2>
          <p className="text-muted-foreground leading-relaxed">Use the calculator to compare platforms and forecast monthly net income before launching or changing prices.</p>
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/digital-product-profit-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



